 337→const isCanvasBackgroundTarget = (target, stage) => {
 338→    if(!target || !stage){
 339→        return false;
 340→    }
 341→
 342→    if(target === stage){
 343→        return true;
 344→    }
 345→
 346→    return target.getParent?.() === stage;
