    );
};

const StampNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected}) => {
    const stamp = STAMP_ICONS[item?.payload?.stamp] || "✨";
    const image = useEmojiImage(stamp, 64);
