 216→const NoteNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected, isDraft}) => {
 217→    const payload = item?.payload || {};
 218→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110, stageWidth * 0.9);
 219→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60, stageHeight * 0.8);
 220→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
 221→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
 222→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
 223→    const bgColor = payload?.bgColor || "#fff4a8";
 224→    const curlSize = Math.min(width, height) * 0.14;
 225→    const pinSize = Math.max(5, Math.min(width, height) * 0.04);
 226→
 227→    const borderStroke = isDraft ? "#a21caf" : isSelected ? "#a21caf" : "rgba(0,0,0,0.1)";
 228→    const borderWidth = isDraft ? 2 : isSelected ? 2 : 0.5;
 229→    const borderDash = isDraft ? [6, 4] : undefined;
 230→
 231→    return (
 232→        <Group
 233→            x={x}
 234→            y={y}
 235→            draggable={canEdit}
 236→            onDragEnd={onDragEnd}
 237→            onClick={onSelect}
 238→            onTap={onSelect}
 239→            rotation={Number(payload?.rotation) || 0}
 240→        >
 241→            {/* Shadow layer beneath the note */}
 242→            <Shape
 243→                sceneFunc={(ctx, shape) => {
 244→                    ctx.beginPath();
 245→                    ctx.moveTo(2, 4);
 246→                    ctx.lineTo(width + 2, 2);
 247→                    ctx.lineTo(width - curlSize + 4, height + 3);
 248→                    ctx.lineTo(2, height + 2);
 249→                    ctx.closePath();
 250→                    ctx.fillStrokeShape(shape);
 251→                }}
 252→                fill="rgba(0,0,0,0.12)"
 253→                listening={false}
 254→            />
 255→
 256→            {/* Main note body */}
 257→            <Shape
 258→                sceneFunc={(ctx, shape) => {
 259→                    ctx.beginPath();
 260→                    ctx.moveTo(0, 0);
 261→                    ctx.lineTo(width, 0);
 262→                    ctx.lineTo(width, height - curlSize);
 263→                    ctx.lineTo(width - curlSize, height);
 264→                    ctx.lineTo(0, height);
 265→                    ctx.closePath();
 266→                    ctx.fillStrokeShape(shape);
 267→                }}
 268→                fill={bgColor}
 269→                stroke={borderStroke}
 270→                strokeWidth={borderWidth}
 271→                dash={borderDash}
 272→            />
 273→
 274→            {/* Page curl triangle */}
 275→            <Shape
 276→                sceneFunc={(ctx, shape) => {
 277→                    ctx.beginPath();
 278→                    ctx.moveTo(width, height - curlSize);
 279→                    ctx.lineTo(width - curlSize, height - curlSize);
 280→                    ctx.lineTo(width - curlSize, height);
 281→                    ctx.closePath();
 282→                    ctx.fillStrokeShape(shape);
 283→                }}
 284→                fill={darkenColor(bgColor, 0.12)}
 285→                listening={false}
 286→            />
 287→
 288→            {/* Curl fold shadow */}
 289→            <Shape
 290→                sceneFunc={(ctx, shape) => {
 291→                    ctx.beginPath();
 292→                    ctx.moveTo(width - curlSize, height);
 293→                    ctx.lineTo(width, height - curlSize);
 294→                    ctx.lineTo(width - curlSize * 0.55, height - curlSize * 0.55);
 295→                    ctx.closePath();
 296→                    ctx.fillStrokeShape(shape);
 297→                }}
 298→                fill="rgba(0,0,0,0.06)"
 299→                listening={false}
 300→            />
 301→
 302→            {/* Text content */}
 303→            <Text
 304→                x={12}
 305→                y={pinSize * 2 + 10}
 306→                width={width - 24}
 307→                height={height - pinSize * 2 - curlSize - 16}
 308→                text={payload?.text || ""}
 309→                fontFamily={payload?.fontFamily || "Arial"}
 310→                fontStyle={fontStyle}
 311→                fontSize={clamp(Number(payload?.fontSize) || 16, 10, 64)}
 312→                fill={payload?.fontColor || "#1f2937"}
 313→                wrap="word"
 314→                lineHeight={1.3}
 315→            />
 316→
 317→            {/* Left push pin */}
 318→            <Circle x={width * 0.18} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 319→            <Line points={[width * 0.18, pinSize * 2 + 2, width * 0.18, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 320→
 321→            {/* Right push pin */}
 322→            <Circle x={width * 0.82} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 323→            <Line points={[width * 0.82, pinSize * 2 + 2, width * 0.82, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 324→
 325→            {/* Pin highlights (glossy effect) */}
 326→            <Circle x={width * 0.18 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 327→            <Circle x={width * 0.82 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 328→        </Group>
 329→    );
 330→};
