                                    type="button"
                                    className={`fw-stamp-btn fw-sticker-btn ${selectedSticker === stickerKey ? "is-active" : ""}`}
                                    onClick={() => setSelectedSticker(stickerKey)}
                                >
                                    {icon}
                                </button>
                            ))}
                        </div>
                    </div>
