                                <button
                                    key={stampKey}
                                    type="button"
                                    className={`fw-stamp-btn ${selectedStamp === stampKey ? "is-active" : ""}`}
                                    onClick={() => setSelectedStamp(stampKey)}
                                >
                                    {icon}
                                </button>
                            ))}
