 132→const useEmojiImage = (emoji, size) => {
 133→    const [image, setImage] = useState(null);
 134→
 135→    useEffect(() => {
 136→        if(!emoji){
 137→            setImage(null);
 138→            return;
 139→        }
 140→
 141→        const cacheKey = `${emoji}_${size}`;
 142→        if(emojiCanvasCache.has(cacheKey)){
 143→            setImage(emojiCanvasCache.get(cacheKey));
 144→            return;
 145→        }
 146→
 147→        const canvas = document.createElement("canvas");
 148→        const scale = window.devicePixelRatio || 1;
 149→        canvas.width = size * scale;
 150→        canvas.height = size * scale;
 151→        const ctx = canvas.getContext("2d");
 152→        ctx.scale(scale, scale);
 153→        ctx.textAlign = "center";
 154→        ctx.textBaseline = "middle";
 155→        ctx.font = `${size * 0.82}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", "Android Emoji", sans-serif`;
 156→        ctx.fillText(emoji, size / 2, size / 2);
 157→
 158→        const img = new window.Image();
 159→        img.onload = () => {
 160→            emojiCanvasCache.set(cacheKey, img);
 161→            setImage(img);
 162→        };
 163→        img.src = canvas.toDataURL();
 164→    }, [emoji, size]);
 165→
 166→    return image;
 167→};
