 451→    const upsertStampCache = useCallback((stamp) => {
 452→        if(!stamp?.id){
 453→            return;
 454→        }
 455→
 456→        queryClient.setQueryData(stampsQueryKey, (old) => {
 457→            const previous = Array.isArray(old?.stamps) ? old.stamps : [];
 458→            const existingIndex = previous.findIndex((item) => String(item?.id) === String(stamp.id));
 459→            let nextStamps = previous;
 460→
 461→            if(existingIndex === -1){
 462→                nextStamps = [...previous, stamp];
 463→            } else {
 464→                nextStamps = [...previous];
 465→                nextStamps[existingIndex] = {...nextStamps[existingIndex], ...stamp};
 466→            }
 467→
 468→            nextStamps.sort(sortByCreatedAt);
 469→            return {...(old || {}), stamps: nextStamps};
 470→        });
 471→    }, [queryClient, stampsQueryKey]);
