 473→    const upsertMarginCache = useCallback((item) => {
 474→        if(!item?.id){
 475→            return;
 476→        }
 477→
 478→        queryClient.setQueryData(marginsQueryKey, (old) => {
 479→            const previous = Array.isArray(old?.items) ? old.items : [];
 480→            const existingIndex = previous.findIndex((entry) => String(entry?.id) === String(item.id));
 481→            let nextItems = previous;
 482→
 483→            if(existingIndex === -1){
 484→                nextItems = [...previous, item];
 485→            } else {
 486→                nextItems = [...previous];
 487→                nextItems[existingIndex] = {...nextItems[existingIndex], ...item};
 488→            }
 489→
 490→            nextItems.sort(sortByCreatedAt);
 491→            return {...(old || {}), items: nextItems};
 492→        });
 493→    }, [marginsQueryKey, queryClient]);
