 525→    const eventBelongsToJournal = useCallback((payload) => {
 526→        const journalIdAsString = String(journalId);
 527→        const newJournalId = payload?.new?.journal_id;
 528→        const oldJournalId = payload?.old?.journal_id;
 529→
 530→        if(newJournalId !== undefined){
 531→            return String(newJournalId) === journalIdAsString;
 532→        }
 533→        if(oldJournalId !== undefined){
 534→            return String(oldJournalId) === journalIdAsString;
