 558→        });
 559→    }, []);
 560→
 561→    const flushQueuedDoodleBroadcast = useCallback(() => {
 562→        if(!pendingDoodlePayloadRef.current){
 563→            return;
 564→        }
 565→
 566→        const nextPayload = pendingDoodlePayloadRef.current;
 567→        pendingDoodlePayloadRef.current = null;
 568→        lastDoodleBroadcastAtRef.current = Date.now();
 569→        sendBroadcastEvent(LIVE_DOODLE_BROADCAST_EVENT, nextPayload);
 570→    }, [sendBroadcastEvent]);
 571→
 572→    const queueDoodleBroadcast = useCallback((payload, immediate = false) => {
 573→        pendingDoodlePayloadRef.current = payload;
 574→        if(immediate){
 575→            clearQueuedDoodleBroadcast();
 576→            flushQueuedDoodleBroadcast();
 577→            return;
 578→        }
 579→
 580→        const elapsed = Date.now() - lastDoodleBroadcastAtRef.current;
 581→        const delay = Math.max(0, LIVE_DOODLE_BROADCAST_INTERVAL_MS - elapsed);
 582→        if(doodleBroadcastTimerRef.current){
 583→            return;
 584→        }
 585→
 586→        doodleBroadcastTimerRef.current = setTimeout(() => {
 587→            doodleBroadcastTimerRef.current = null;
 588→            flushQueuedDoodleBroadcast();
