 609→        const journalIdAsString = String(journalId);
 610→        const realtimeChannelName = `canvas-live-${journalIdAsString}-${Math.random().toString(36).slice(2, REALTIME_CHANNEL_SUFFIX_LENGTH + 2)}`;
 611→
 612→        const channel = supabase
 613→        .channel(realtimeChannelName)
 614→        .on(
 615→            "postgres_changes",
 616→            {event: "*", schema: "public", table: "canvas_stamps", filter: `journal_id=eq.${journalIdAsString}`},
 617→            (payload) => {
 618→                if(payload?.eventType === "DELETE"){
 619→                    if(payload?.old?.id){
 620→                        removeStampFromCache(payload.old.id);
 621→                    }
 622→                    return;
 623→                }
 624→
 625→                const nextStamp = normalizeStampRow(payload?.new);
 626→                if(nextStamp){
 627→                    upsertStampCache(nextStamp);
 628→                }
 629→            }
 630→        )
 631→        .on(
 632→            "postgres_changes",
 633→            {event: "DELETE", schema: "public", table: "canvas_stamps"},
 634→            (payload) => {
 635→                const match = eventBelongsToJournal(payload);
 636→                if(match === true && payload?.old?.id){
 637→                    removeStampFromCache(payload.old.id);
 638→                    return;
 639→                }
 640→
 641→                // Fallback for environments where DELETE payload omits journal_id.
 642→                if(match === null){
 643→                    queryClient.invalidateQueries({queryKey: stampsQueryKey});
 644→                }
 645→            }
 646→        )
 647→        .on(
 648→            "postgres_changes",
 649→            {event: "*", schema: "public", table: "canvas_margin_items", filter: `journal_id=eq.${journalIdAsString}`},
 650→            (payload) => {
 651→                if(payload?.eventType === "DELETE"){
 652→                    if(payload?.old?.id){
 653→                        removeMarginFromCache(payload.old.id);
 654→                    }
 655→                    return;
 656→                }
 657→
 658→                const nextMargin = normalizeMarginRow(payload?.new);
 659→                if(nextMargin){
 660→                    upsertMarginCache(nextMargin);
 661→                }
 662→            }
 663→        )
 664→        .on(
 665→            "postgres_changes",
 666→            {event: "DELETE", schema: "public", table: "canvas_margin_items"},
 667→            (payload) => {
 668→                const match = eventBelongsToJournal(payload);
 669→                if(match === true && payload?.old?.id){
 670→                    removeMarginFromCache(payload.old.id);
 671→                    return;
 672→                }
 673→
 674→                // Fallback for environments where DELETE payload omits journal_id.
 675→                if(match === null){
 676→                    queryClient.invalidateQueries({queryKey: marginsQueryKey});
 677→                }
 678→            }
 679→        )
 680→        .on(
 681→            "broadcast",
 682→            {event: LIVE_DOODLE_BROADCAST_EVENT},
 683→            ({payload}) => {
 684→                if(!payload || String(payload?.journalId) !== journalIdAsString){
 685→                    return;
 686→                }
 687→                const remoteClientId = typeof payload?.clientId === "string" ? payload.clientId : "";
 688→                if(!remoteClientId || remoteClientId === viewerClientIdRef.current){
 689→                    return;
 690→                }
 691→
 692→                const points = sanitizeNormalizedPoints(payload?.points);
 693→                if(points.length < 2){
 694→                    return;
 695→                }
 696→
 697→                setLiveDoodlesByClient((prev) => ({
 698→                    ...prev,
 699→                    [remoteClientId]: {
 700→                        clientId: remoteClientId,
 701→                        points: points,
 702→                        color: typeof payload?.color === "string" ? payload.color : "#5f92ff",
 703→                        size: Number(payload?.size) || 2.8,
 704→                        updatedAt: Date.now()
 705→                    }
 706→                }));
 707→            }
 708→        )
 709→        .on(
 710→            "broadcast",
 711→            {event: LIVE_DOODLE_END_EVENT},
 712→            ({payload}) => {
 713→                if(!payload || String(payload?.journalId) !== journalIdAsString){
 714→                    return;
 715→                }
 716→                const remoteClientId = typeof payload?.clientId === "string" ? payload.clientId : "";
 717→                if(!remoteClientId || remoteClientId === viewerClientIdRef.current){
 718→                    return;
 719→                }
 720→
 721→                setLiveDoodlesByClient((prev) => {
 722→                    const next = {...prev};
 723→                    delete next[remoteClientId];
 724→                    return next;
 725→                });
 726→            }
 727→        )
 728→        .subscribe();
 729→
 730→        realtimeChannelRef.current = channel;
 731→
 732→        return () => {
 733→            if(realtimeChannelRef.current === channel){
 734→                realtimeChannelRef.current = null;
 735→            }
 736→            supabase.removeChannel(channel);
 737→        };
 738→    }, [eventBelongsToJournal, journalId, marginsQueryKey, normalizeMarginRow, normalizeStampRow, queryClient, removeMarginFromCache, removeStampFromCache, stampsQueryKey, upsertMarginCache, upsertStampCache]);
 739→
 740→    useEffect(() => {
 741→        setLiveDoodlesByClient({});
 742→    }, [journalId]);
 743→
 744→    useEffect(() => {
 745→        const intervalId = setInterval(() => {
 746→            const now = Date.now();
 747→            setLiveDoodlesByClient((prev) => {
 748→                const next = {};
 749→                let hasChanged = false;
 750→
 751→                Object.entries(prev).forEach(([clientId, value]) => {
 752→                    if(now - (value?.updatedAt || 0) <= LIVE_DOODLE_STALE_MS){
 753→                        next[clientId] = value;
 754→                    } else {
 755→                        hasChanged = true;
 756→                    }
 757→                });
 758→
 759→                return hasChanged ? next : prev;
 760→            });
 761→        }, Math.max(500, Math.round(LIVE_DOODLE_STALE_MS / 2)));
 762→
 763→        return () => {
 764→            clearInterval(intervalId);
 765→        };
 766→    }, []);
 767→
 768→    useEffect(() => {
 769→        return () => {
 770→            clearQueuedDoodleBroadcast();
