  51→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  52→const createOptimisticId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  53→const toTimestamp = (value) => {
  54→    const parsed = Date.parse(value || "");
  55→    return Number.isNaN(parsed) ? 0 : parsed;
  56→};
  57→const sortByCreatedAt = (a, b) => {
  58→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  59→    if(byDate !== 0){
  60→        return byDate;
  61→    }
  62→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  63→};
  64→const sanitizeNormalizedPoints = (rawPoints) => {
  65→    if(!Array.isArray(rawPoints)){
  66→        return [];
  67→    }
  68→
  69→    const numericPoints = rawPoints
  70→        .map((point) => Number(point))
  71→        .filter((point) => !Number.isNaN(point))
  72→        .map((point) => clamp(point, 0, 1));
  73→
  74→    if(numericPoints.length < 2){
  75→        return [];
  76→    }
  77→
  78→    return numericPoints.length % 2 === 0
  79→        ? numericPoints
  80→        : numericPoints.slice(0, -1);
  81→};
