  94→const getSnippetMetrics = (snippet, stageWidth) => {
  95→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  96→    const baseFontSize = snippet.fontStyle === "bold" ? 34 : snippet.fontStyle === "handwritten" ? 32 : 30;
  97→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  98→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  99→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 100→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
 101→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 102→
 103→    return {width: estimatedWidth, height, fontSize};
 104→};
