 334→const formatWeekLabel = (week = null) => {
 335→    if(!week?.week_start || !week?.week_end){
 336→        return "No active week";
 337→    }
 338→
 339→    const startDate = new Date(week.week_start);
 340→    const endDate = new Date(week.week_end);
 341→    return `${startDate.toLocaleDateString()} - ${endDate.toLocaleDateString()} (UTC)`;
 342→};
 343→
 344→const isCanvasBackgroundTarget = (target, stage) => {
 345→    if(!target || !stage){
 346→        return false;
 347→    }
 348→
 349→    if(target === stage){
 350→        return true;
 351→    }
 352→
 353→    return target.getParent?.() === stage;
 354→};
